button:disabled{opacity:.4;cursor:not-allowed}
.erro{display:none;background:rgba(255,59,48,.08);border:1px solid rgba(255,59,48,.3);color:#ff6b6b;font-size:10px;padding:10px 14px;border-radius:3px;margin-bottom:18px}
</style>
</head>
<body>
<div class="card">
  <div class="badge"><div class="dot"></div>Dropbox · YOUR_COMPANY</div>
  <h1>Acesso ao <span>Gerenciador</span></h1>
  <p class="sub">Informe suas credenciais para continuar</p>
  <div class="erro" id="erro">Usuário ou senha inválidos.</div>
  <label for="u">Usuário</label>
  <input type="text" id="u" placeholder="seu usuário">
  <label for="p">Senha</label>
  <input type="password" id="p" placeholder="••••••••">
  <button id="btn" onclick="entrar()">Entrar</button>
</div>
<script>
document.getElementById('p').onkeydown = function(e){ if(e.key==='Enter') entrar(); };
document.getElementById('u').onkeydown = function(e){ if(e.key==='Enter') document.getElementById('p').focus(); };

function entrar(){
  var u   = document.getElementById('u').value.trim();
  var p   = document.getElementById('p').value;
  var btn = document.getElementById('btn');
  var err = document.getElementById('erro');

  if(!u || !p){
    err.textContent = 'Preencha usuário e senha.';
    err.style.display = 'block';
    return;
  }

  btn.disabled = true;
  btn.textContent = 'Aguarde...';
  err.style.display = 'none';

  fetch('/webhook/dropbox-auth', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ user: u, pwd: p })
  })
  .then(function(r) {
    if (r.status === 200) {
      return r.text().then(function(html) {
        document.open(); document.write(html); document.close();
      });
    }
    btn.disabled = false;
    btn.textContent = 'Entrar';
    err.textContent = 'Usuário ou senha inválidos.';
    err.style.display = 'block';
  })
  .catch(function() {
    btn.disabled = false;
    btn.textContent = 'Entrar';
    err.textContent = 'Erro de conexão. Tente novamente.';
    err.style.display = 'block';
  });
}
</script>
</body>
</html>

