const rows = $input.all();

// Usuário não existe (linha vazia do Always Output Data)
if (!rows[0].json.user) {
  return [{ json: { valid: false } }];
}

// Compara a senha digitada com a que está na DataTable
const senhaDigitada = $('Dropbox-Auth').first().json.body.pwd;
const senhaCorreta  = rows[0].json.pwd;

return [{ json: { valid: senhaDigitada === senhaCorreta } }];

const staticData = $getWorkflowStaticData('global');

if (!staticData.entries) staticData.entries = [];

const PASTAS_EXCLUIDAS = [
  '/YOUR_FOLDER_PATH/SubFolder1',
  '/YOUR_FOLDER_PATH/SubFolder2',
  '/YOUR_FOLDER_PATH/SubFolder3'
];

const entries = $json.entries || [];

const soArquivos = entries.filter(function(e) {
  if (e['.tag'] !== 'file') return false;
  return !PASTAS_EXCLUIDAS.some(function(pasta) {
    return e.path_lower.startsWith(pasta.toLowerCase());
  });
});

staticData.entries.push(...soArquivos);

return [{
  json: {
    has_more:       $json.has_more,
    cursor:         $json.cursor,
    total_arquivos: staticData.entries.length,
    total_pag:      soArquivos.length,
    total_bruto:    entries.length
  }
}];

const staticData = $getWorkflowStaticData('global');

staticData.space = {
  used:      $json.used,
  allocated: $json.allocation.allocated,
  team_used: $json.used
};

// Passa os dados adiante para o list_folder continuar
return [{ json: $json }];

const staticData = $getWorkflowStaticData('global');
const todos = staticData.entries || [];

// Deduplica por id e filtra mínimo de 100 MB
const MIN_BYTES = 100 * 1024 * 1024;
const vistos = {};
const arquivos = todos.filter(function(e) {
  if (e['.tag'] !== 'file' || !e.server_modified || !e.size) return false;
  if (e.size < MIN_BYTES) return false;
  if (vistos[e.id]) return false;
  vistos[e.id] = true;
  return true;
});

// Normaliza idade e tamanho na mesma escala (0 a 1) antes de calcular o score
const agora = Date.now();

const maxIdade = Math.max.apply(null, arquivos.map(function(f) {
  return agora - new Date(f.server_modified).getTime();
}));

const maxTamanho = Math.max.apply(null, arquivos.map(function(f) {
  return f.size || 0;
}));

const ordenados = arquivos.sort(function(a, b) {
  var idadeNormA = (agora - new Date(a.server_modified).getTime()) / maxIdade;
  var idadeNormB = (agora - new Date(b.server_modified).getTime()) / maxIdade;
  var tamNormA   = (a.size || 0) / maxTamanho;
  var tamNormB   = (b.size || 0) / maxTamanho;
  var scoreA = (tamNormA * 0.6) + (idadeNormA * 0.4);
  var scoreB = (tamNormB * 0.6) + (idadeNormB * 0.4);
  return scoreB - scoreA;
});

staticData.entries = [];

const top50 = ordenados.slice(0, 50);

// ── Espaço Dropbox ────────────────────────────────────────────
var space = staticData.space || {};
var TB = 1099511627776;

var spaceTotal  = space.allocated ? (space.allocated / TB).toFixed(2) + ' TB' : '--';
var spaceUsed   = space.team_used ? (space.team_used  / TB).toFixed(2) + ' TB' : '--';
var spaceFree   = (space.allocated && space.team_used)
  ? ((space.allocated - space.team_used) / TB).toFixed(2) + ' TB' : '--';
var spacePct    = (space.allocated && space.team_used)
  ? ((space.team_used / space.allocated) * 100).toFixed(1) + '%' : '--';
var spaceAlert  = space.allocated && space.team_used
  && (space.team_used / space.allocated) > 0.85;
var spacePctNum = space.allocated && space.team_used
  ? ((space.team_used / space.allocated) * 100).toFixed(1)
  : '0';

// ── Utilitários ───────────────────────────────────────────────
function fmtDate(iso) {
  if (!iso) return '--';
  var d = new Date(iso);
  return d.toLocaleDateString('pt-BR') + ' ' +
         d.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
}

function timeAgo(iso) {
  var diff = Date.now() - new Date(iso);
  var d = Math.floor(diff / 86400000);
  if (d < 1)  return 'hoje';
  if (d < 30) return d + 'd atras';
  var m = Math.floor(d / 30);
  if (m < 12) return '~' + m + ' meses atras';
  return '~' + Math.floor(m / 12) + ' ano(s) atras';
}

function fmtSize(bytes) {
  var mb = bytes / 1048576;
  if (mb >= 1024) return (mb / 1024).toFixed(2) + ' GB';
  return mb.toFixed(0) + ' MB';
}

function dropboxUrl(pathDisplay) {
  var pasta = pathDisplay.substring(0, pathDisplay.lastIndexOf('/'));
  return 'https://www.dropbox.com/home' + pasta.replace(/ /g, '%20');
}

// ── Stats dos arquivos ────────────────────────────────────────
var totalBytes = top50.reduce(function(s, f) { return s + (f.size || 0); }, 0);
var maxBytes   = Math.max.apply(null, top50.map(function(f) { return f.size || 0; }));
var oldest     = top50.slice().sort(function(a,b){ return new Date(a.server_modified) - new Date(b.server_modified); })[0];
var heaviest   = top50.slice().sort(function(a, b) { return b.size - a.size; })[0];

var totalStr = totalBytes >= 1073741824
  ? (totalBytes / 1073741824).toFixed(2) + ' GB'
  : (totalBytes / 1048576).toFixed(0) + ' MB';

// ── Linhas da tabela ──────────────────────────────────────────
var rows = top50.map(function(f, i) {
  var pct = Math.min(100, ((f.size || 0) / maxBytes) * 100).toFixed(1);
  var big = (f.size || 0) > 1073741824;
  var bar = big
    ? 'background:linear-gradient(90deg,#ff6b2b,#ff3b30)'
    : 'background:linear-gradient(90deg,#0061fe,#00c2ff)';
  var url = dropboxUrl(f.path_display);

  return '<tr>'
    + '<td style="text-align:center;color:#5a5a72;font-size:10px;padding:10px 14px">' + (i + 1) + '</td>'
    + '<td style="padding:10px 14px;font-family:monospace;font-size:11px">'
      + '<span style="color:#e8e8f0;font-weight:700;display:block;word-break:break-word">' + f.name + '</span>'
      + '<span style="color:#5a5a72;font-size:9px;display:block;word-break:break-all;margin-top:2px">' + f.path_display + '</span>'
      + '<button class="cbtn" data-url="' + url + '" '
        + 'style="margin-top:6px;background:rgba(0,97,254,.1);border:1px solid rgba(0,97,254,.3);'
        + 'color:#00c2ff;font-family:monospace;font-size:9px;letter-spacing:.5px;'
        + 'padding:3px 9px;border-radius:2px;cursor:pointer">'
        + '&#128203; Copiar link Dropbox'
      + '</button>'
    + '</td>'
    + '<td style="padding:10px 14px;font-family:monospace;font-size:11px;white-space:nowrap">'
      + fmtDate(f.server_modified)
      + '<span style="display:block;color:#5a5a72;font-size:9px;margin-top:2px">' + timeAgo(f.server_modified) + '</span>'
    + '</td>'
    + '<td style="padding:10px 14px;font-family:monospace;font-size:11px;text-align:right;white-space:nowrap">'
      + '<span style="display:block">' + fmtSize(f.size || 0) + '</span>'
      + '<div style="height:3px;background:rgba(255,255,255,0.05);border-radius:2px;margin-top:5px;width:80px;margin-left:auto">'
        + '<div style="height:100%;width:' + pct + '%;border-radius:2px;' + bar + '"></div>'
      + '</div>'
    + '</td>'
    + '</tr>';
}).join('');

// ── DATA para JS ──────────────────────────────────────────────
var dataJson = JSON.stringify(top50.map(function(f) {
  return {
    name: f.name,
    path: f.path_display,
    url:  dropboxUrl(f.path_display),
    date: f.server_modified,
    size: f.size || 0
  };
}));

// ── HTML Final ────────────────────────────────────────────────
